#!/usr/bin/env python3# -*- coding: utf-8 -*-import kerasimport numpy as npimport matplotlib.pyplot as pltclass CleanLRLogger(keras.callbacks.Callback):    def on_epoch_begin(self, epoch, logs=None):        # 1. Get the current step        step = self.model.optimizer.iterations        lr_obj = self.model.optimizer.learning_rate                # 2. Extract value safely        if hasattr(lr_obj, '__call__'):            current_lr = lr_obj(step)        else:            current_lr = lr_obj                    # 3. Inject into the logs dictionary so Keras prints it for us        # We use float() to ensure compatibility with the progress bar        if logs is not None:            logs['lr'] = float(current_lr)                def on_epoch_end(self, epoch, logs=None):        # Repeat for the end of the epoch to ensure the final summary is correct        lr_obj = self.model.optimizer.learning_rate        if hasattr(lr_obj, '__call__'):            current_lr = lr_obj(self.model.optimizer.iterations)        else:            current_lr = lr_obj                    if logs is not None:            logs['lr'] = float(current_lr)            def plot_sim_samples(draws, truth, backtransform, label="parameter"):    """        Parameters    ----------    draws : 1D array        DESCRIPTION.    truth : scalary        true parameter value    backtransform : function        backtransform function for samples and truth value    parameter : string        label of backtransformed parameters    Returns    -------    plot of samples    """    draws_transformed = backtransform(draws)    truth_transformed = np.round(backtransform(truth), 4).item()    plt.figure()    plt.hist(draws_transformed)    plt.xlabel(label)    plt.ylabel("Frequency")    plt.title(rf"Posterior samples of {label}, true value: {truth_transformed}")    ci95 = np.quantile(draws_transformed, [0.025, 0.975])    plt.axvline(x = truth_transformed, color = "r",                linestyle='--', label='Truth')    plt.axvline(x = ci95[0].item(), color = "b",                linestyle='--', label='95% CI (lower)')    plt.axvline(x = ci95[1].item(), color = "b",                linestyle='--', label='95% CI (upper)')    plt.legend()    def simulateChainSamples(n_samples, data, X, beta_approx, var_approx):    """        Parameters    ----------    n_samples : int        number of samples to draw    data : dict        dict containing {y: (batch_size, n, 1) np.array}    beta_approx : ContinuousApproximator        a Bayesflow approximator for BYM2 fixed effects    var_approx : ContinuousApproximator        a Bayesflow approximator for BYM2 variance parameters conditional on X\beta    Returns    -------    dict{        'y': (batch_size, n, 1) array            original response data        "beta": (batch_size, n_samples, p) array            fixed effects posterior samples        "mu": (batch_size, n_samples, n) array            predictive mean posterior samples        "log_sigma2": (batch_size, n_samples, 1) array            log total error variance posterior samples        "logit_rho": (batch_size, n_samples, 1) array            logit spatial proportion of variance posterior samples        }    """    batches = data["y"].shape[0]    n = data["y"].shape[1]    beta_draws = beta_approx.sample(conditions = data, num_samples = n_samples)    beta_draws = beta_draws['beta']    var_data = dict()    var_data["y"] = np.repeat(data['y'], repeats = n_samples, axis = 0)        mu_draws = np.repeat(beta_draws[:,:,0][:, :, np.newaxis],                         repeats = n, axis = 2)    mu_draws += np.einsum("bij,kj->bik", beta_draws[:,:,1:], X)    var_data["mu"] = np.reshape(mu_draws, (batches * n_samples, n, 1))    var_draws = var_approx.sample(conditions = var_data, num_samples = 1)    output = {        "y" : data["y"],        "beta" : beta_draws,        "mu" : mu_draws,        "log_sigma2" : np.reshape(var_draws["log_sigma2"], (batches, n_samples, 1)),        "logit_rho" : np.reshape(var_draws["logit_rho"], (batches, n_samples, 1)),    }    return output